namespace sv_816adc0d3a4f4d02b87c936cacd52865.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@page "/apply"
@using sv_816adc0d3a4f4d02b87c936cacd52865.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<h1>Job Application</h1>

@* Step Indicator Bar *@
<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var stepClass = GetStepClass(stepIndex);
        <button class="step @stepClass"
                disabled="@(!IsStepClickable(stepIndex))"
                @onclick="() => GoToStep(stepIndex)">
            @if (stepIndex < CurrentStep)
            {
                <span class="step-icon">&#10003;</span>
            }
            else
            {
                <span class="step-number">@(stepIndex + 1)</span>
            }
            <span class="step-label">@StepNames[stepIndex]</span>
        </button>
        @if (i < StepNames.Length - 1)
        {
            <span class="step-connector"></span>
        }
    }
</nav>

@* Step Content *@
<div class="step-content">
    @if (CurrentStep == 0)
    {
        @* Step 1: Personal Info *@
        <h2>Personal Information</h2>
        <div class="form-group">
            <label for="fullName">Full Name *</label>
            <input id="fullName" type="text" @bind="FullName" @bind:event="oninput" />
        </div>
        <div class="form-group">
            <label for="email">Email *</label>
            <input id="email" type="email" @bind="Email" @bind:event="oninput" />
        </div>
        <div class="form-group">
            <label for="phone">Phone *</label>
            <input id="phone" type="tel" @bind="Phone" @bind:event="oninput" />
        </div>
        <div class="form-group">
            <label for="address">Address *</label>
            <input id="address" type="text" @bind="Address" @bind:event="oninput" />
        </div>

        @if (!string.IsNullOrEmpty(ValidationError))
        {
            <div class="validation-error">@ValidationError</div>
        }

        <div class="form-actions">
            <button class="btn-next" @onclick="NextFromPersonalInfo" disabled="@IsLoading">
                @if (IsLoading)
                {
                    <span>Validating...</span>
                }
                else
                {
                    <span>Next</span>
                }
            </button>
        </div>
    }
    else if (CurrentStep == 1)
    {
        @* Step 2: Work History *@
        <h2>Work History</h2>
        @for (int i = 0; i < WorkEntries.Count; i++)
        {
            var index = i;
            <fieldset class="work-entry">
                <legend>Position @(index + 1)</legend>
                <div class="form-group">
                    <label>Company Name *</label>
                    <input type="text" value="@WorkEntries[index].Company"
                           @onchange="(e) => UpdateWorkEntry(index, nameof(WorkEntryModel.Company), e.Value)" />
                </div>
                <div class="form-group">
                    <label>Job Title *</label>
                    <input type="text" value="@WorkEntries[index].Title"
                           @onchange="(e) => UpdateWorkEntry(index, nameof(WorkEntryModel.Title), e.Value)" />
                </div>
                <div class="form-group">
                    <label>Start Date *</label>
                    <input type="date" value="@WorkEntries[index].StartDate?.ToString("yyyy-MM-dd")"
                           @onchange="(e) => UpdateWorkEntry(index, nameof(WorkEntryModel.StartDate), e.Value)" />
                </div>
                <div class="form-group">
                    <label>
                        <input type="checkbox" checked="@WorkEntries[index].IsCurrent"
                               @onchange="(e) => UpdateWorkEntry(index, nameof(WorkEntryModel.IsCurrent), e.Value)" />
                        Currently working here
                    </label>
                </div>
                @if (!WorkEntries[index].IsCurrent)
                {
                    <div class="form-group">
                        <label>End Date</label>
                        <input type="date" value="@WorkEntries[index].EndDate?.ToString("yyyy-MM-dd")"
                               @onchange="(e) => UpdateWorkEntry(index, nameof(WorkEntryModel.EndDate), e.Value)" />
                    </div>
                }
                <div class="form-group">
                    <label>Description *</label>
                    <textarea value="@WorkEntries[index].Description"
                              @onchange="(e) => UpdateWorkEntry(index, nameof(WorkEntryModel.Description), e.Value)"></textarea>
                </div>
                @if (WorkEntries.Count > 1)
                {
                    <button class="btn-remove" @onclick="() => RemoveWorkEntry(index)">Remove</button>
                }
            </fieldset>
        }
        <button class="btn-add" @onclick="AddWorkEntry">+ Add Another Position</button>

        @if (!string.IsNullOrEmpty(ValidationError))
        {
            <div class="validation-error">@ValidationError</div>
        }

        <div class="form-actions">
            <button class="btn-back" @onclick="PreviousStep">Back</button>
            <button class="btn-next" @onclick="NextFromWorkHistory">Next</button>
        </div>
    }
    else if (CurrentStep == 2)
    {
        @* Step 3: References *@
        <h2>References</h2>
        @for (int i = 0; i < References.Count; i++)
        {
            var index = i;
            <fieldset class="reference-entry">
                <legend>Reference @(index + 1)</legend>
                <div class="form-group">
                    <label>Name *</label>
                    <input type="text" value="@References[index].Name"
                           @onchange="(e) => UpdateReference(index, nameof(ReferenceModel.Name), e.Value)" />
                </div>
                <div class="form-group">
                    <label>Relationship *</label>
                    <input type="text" value="@References[index].Relationship"
                           @onchange="(e) => UpdateReference(index, nameof(ReferenceModel.Relationship), e.Value)" />
                </div>
                <div class="form-group">
                    <label>Email *</label>
                    <input type="email" value="@References[index].Email"
                           @onchange="(e) => UpdateReference(index, nameof(ReferenceModel.Email), e.Value)" />
                </div>
                <div class="form-group">
                    <label>Phone *</label>
                    <input type="tel" value="@References[index].Phone"
                           @onchange="(e) => UpdateReference(index, nameof(ReferenceModel.Phone), e.Value)" />
                </div>
                @if (References.Count > 2)
                {
                    <button class="btn-remove" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </fieldset>
        }
        @if (References.Count < 3)
        {
            <button class="btn-add" @onclick="AddReference">+ Add Reference</button>
        }

        @if (!string.IsNullOrEmpty(ValidationError))
        {
            <div class="validation-error">@ValidationError</div>
        }

        <div class="form-actions">
            <button class="btn-back" @onclick="PreviousStep">Back</button>
            <button class="btn-next" @onclick="NextFromReferences">Next</button>
        </div>
    }
    else if (CurrentStep == 3)
    {
        @* Step 4: Cover Letter *@
        <h2>Cover Letter</h2>
        <div class="form-group">
            <textarea class="cover-letter-input" maxlength="2000"
                      @bind="CoverLetter" @bind:event="oninput"
                      placeholder="Write your cover letter here..."></textarea>
            <div class="character-count">@CoverLetter.Length / 2000 characters</div>
        </div>

        @if (!string.IsNullOrEmpty(ValidationError))
        {
            <div class="validation-error">@ValidationError</div>
        }

        <div class="form-actions">
            <button class="btn-back" @onclick="PreviousStep">Back</button>
            <button class="btn-next" @onclick="NextFromCoverLetter">Next</button>
        </div>
    }
    else if (CurrentStep == 4)
    {
        @* Step 5: Review & Submit *@
        @if (IsSubmitted)
        {
            <div class="submission-confirmation">
                <h2>Application Submitted!</h2>
                <p>Your application has been successfully submitted.</p>
                <p><strong>Application ID: @SubmittedApplicationId</strong></p>
            </div>
        }
        else
        {
            <h2>Review &amp; Submit</h2>

            <section class="review-section">
                <h3>Personal Information <a class="edit-link" @onclick="() => GoToStep(0)">Edit</a></h3>
                <dl>
                    <dt>Full Name</dt><dd>@FullName</dd>
                    <dt>Email</dt><dd>@Email</dd>
                    <dt>Phone</dt><dd>@Phone</dd>
                    <dt>Address</dt><dd>@Address</dd>
                </dl>
            </section>

            <section class="review-section">
                <h3>Work History <a class="edit-link" @onclick="() => GoToStep(1)">Edit</a></h3>
                @foreach (var entry in WorkEntries)
                {
                    <div class="review-work-entry">
                        <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                        <span>@entry.StartDate?.ToString("MMM yyyy") — @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))</span><br />
                        <p>@entry.Description</p>
                    </div>
                }
            </section>

            <section class="review-section">
                <h3>References <a class="edit-link" @onclick="() => GoToStep(2)">Edit</a></h3>
                @foreach (var reference in References)
                {
                    <div class="review-reference">
                        <strong>@reference.Name</strong> (@reference.Relationship)<br />
                        <span>@reference.Email | @reference.Phone</span>
                    </div>
                }
            </section>

            <section class="review-section">
                <h3>Cover Letter <a class="edit-link" @onclick="() => GoToStep(3)">Edit</a></h3>
                <p class="cover-letter-preview">@CoverLetter</p>
            </section>

            @if (!string.IsNullOrEmpty(ValidationError))
            {
                <div class="validation-error">@ValidationError</div>
            }

            <div class="form-actions">
                <button class="btn-back" @onclick="PreviousStep">Back</button>
                <button class="btn-submit" @onclick="SubmitApplication" disabled="@IsLoading">
                    @if (IsLoading)
                    {
                        <span>Submitting...</span>
                    }
                    else
                    {
                        <span>Submit Application</span>
                    }
                </button>
            </div>
        }
    }
</div>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    private int CurrentStep { get; set; }
    private string ValidationError { get; set; } = string.Empty;
    private bool IsLoading { get; set; }
    private bool IsSubmitted { get; set; }
    private int SubmittedApplicationId { get; set; }

    // Step 1 fields
    private string FullName { get; set; } = string.Empty;
    private string Email { get; set; } = string.Empty;
    private string Phone { get; set; } = string.Empty;
    private string Address { get; set; } = string.Empty;

    // Step 2 fields
    private List<WorkEntryModel> WorkEntries { get; set; } = new() { new WorkEntryModel() };

    // Step 3 fields
    private List<ReferenceModel> References { get; set; } = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4 field
    private string CoverLetter { get; set; } = string.Empty;

    private string GetStepClass(int stepIndex)
    {
        if (stepIndex == CurrentStep) return "active";
        if (stepIndex < CurrentStep) return "completed";
        return "future";
    }

    private bool IsStepClickable(int stepIndex) => stepIndex < CurrentStep;

    private void GoToStep(int step)
    {
        if (step < CurrentStep)
        {
            CurrentStep = step;
            ValidationError = string.Empty;
        }
    }

    private void PreviousStep()
    {
        if (CurrentStep > 0)
        {
            CurrentStep--;
            ValidationError = string.Empty;
        }
    }

    private async Task NextFromPersonalInfo()
    {
        ValidationError = string.Empty;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email) ||
            string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ValidationError = "All fields are required.";
            return;
        }

        IsLoading = true;
        try
        {
            var isEmailValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!isEmailValid)
            {
                ValidationError = "The email address is not valid.";
                return;
            }
            CurrentStep++;
        }
        finally
        {
            IsLoading = false;
        }
    }

    private void NextFromWorkHistory()
    {
        ValidationError = string.Empty;

        foreach (var entry in WorkEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null || string.IsNullOrWhiteSpace(entry.Description))
            {
                ValidationError = "Please fill in all required fields for each position.";
                return;
            }
        }
        CurrentStep++;
    }

    private void NextFromReferences()
    {
        ValidationError = string.Empty;

        foreach (var reference in References)
        {
            if (string.IsNullOrWhiteSpace(reference.Name) || string.IsNullOrWhiteSpace(reference.Relationship) ||
                string.IsNullOrWhiteSpace(reference.Email) || string.IsNullOrWhiteSpace(reference.Phone))
            {
                ValidationError = "Please fill in all required fields for each reference.";
                return;
            }
        }
        CurrentStep++;
    }

    private void NextFromCoverLetter()
    {
        ValidationError = string.Empty;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ValidationError = "Please write a cover letter.";
            return;
        }
        CurrentStep++;
    }

    private async Task SubmitApplication()
    {
        ValidationError = string.Empty;
        IsLoading = true;

        try
        {
            var personal = new PersonalInfo(FullName, Email, Phone, Address);
            var workHistory = new WorkHistory(WorkEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate!.Value, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
            var references = References.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, workHistory, references, CoverLetter);

            SubmittedApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            ValidationError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsLoading = false;
        }
    }

    // Work entry helpers
    private void AddWorkEntry() => WorkEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (WorkEntries.Count > 1)
            WorkEntries.RemoveAt(index);
    }

    private void UpdateWorkEntry(int index, string field, object? value)
    {
        var entry = WorkEntries[index];
        switch (field)
        {
            case nameof(WorkEntryModel.Company): entry.Company = value?.ToString() ?? ""; break;
            case nameof(WorkEntryModel.Title): entry.Title = value?.ToString() ?? ""; break;
            case nameof(WorkEntryModel.StartDate):
                entry.StartDate = DateTime.TryParse(value?.ToString(), out var sd) ? sd : null;
                break;
            case nameof(WorkEntryModel.EndDate):
                entry.EndDate = DateTime.TryParse(value?.ToString(), out var ed) ? ed : null;
                break;
            case nameof(WorkEntryModel.IsCurrent): entry.IsCurrent = value is true or "True" or "true"; break;
            case nameof(WorkEntryModel.Description): entry.Description = value?.ToString() ?? ""; break;
        }
    }

    // Reference helpers
    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private void UpdateReference(int index, string field, object? value)
    {
        var reference = References[index];
        switch (field)
        {
            case nameof(ReferenceModel.Name): reference.Name = value?.ToString() ?? ""; break;
            case nameof(ReferenceModel.Relationship): reference.Relationship = value?.ToString() ?? ""; break;
            case nameof(ReferenceModel.Email): reference.Email = value?.ToString() ?? ""; break;
            case nameof(ReferenceModel.Phone): reference.Phone = value?.ToString() ?? ""; break;
        }
    }

    // Mutable models for form state
    private class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime? StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

.step-indicator {
    display: flex;
    align-items: center;
    gap: 0.25rem;
    margin-bottom: 2rem;
    flex-wrap: wrap;
}

.step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.5rem 1rem;
    border: 1px solid #ccc;
    border-radius: 2rem;
    background: #f5f5f5;
    cursor: default;
    font-size: 0.9rem;
    transition: all 0.2s;
}

.step.active {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
    font-weight: bold;
}

.step.completed {
    background: #198754;
    color: white;
    border-color: #198754;
    cursor: pointer;
}

.step.completed:hover {
    opacity: 0.85;
}

.step.future {
    opacity: 0.5;
}

.step:disabled {
    cursor: default;
}

.step-connector {
    width: 1.5rem;
    height: 2px;
    background: #ccc;
}

.step-icon, .step-number {
    font-weight: bold;
}

.step-content {
    max-width: 700px;
}

.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.3rem;
    font-weight: 500;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="tel"],
.form-group input[type="date"],
.form-group textarea {
    width: 100%;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
    box-sizing: border-box;
}

.form-group textarea {
    min-height: 100px;
    resize: vertical;
}

.cover-letter-input {
    min-height: 250px !important;
