toolArgs.file_text:
.step-indicator {
    display: flex;
    align-items: center;
    gap: 0.25rem;
    margin-bottom: 2rem;
    flex-wrap: wrap;
}

.step {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.5rem 1rem;
    border: 1px solid #ccc;
    border-radius: 2rem;
    background: #f5f5f5;
    cursor: default;
    font-size: 0.9rem;
    transition: all 0.2s;
}

.step.active {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
    font-weight: bold;
}

.step.completed {
    background: #198754;
    color: white;
    border-color: #198754;
    cursor: pointer;
}

.step.completed:hover {
    opacity: 0.85;
}

.step.future {
    opacity: 0.5;
}

.step:disabled {
    cursor: default;
}

.step-connector {
    width: 1.5rem;
    height: 2px;
    background: #ccc;
}

.step-icon, .step-number {
    font-weight: bold;
}

.step-content {
    max-width: 700px;
}

.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.3rem;
    font-weight: 500;
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="tel"],
.form-group input[type="date"],
.form-group textarea {
    width: 100%;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
    box-sizing: border-box;
}

.form-group textarea {
    min-height: 100px;
    resize: vertical;
}

.cover-letter-input {
    min-height: 250px !important;
}

.character-count {
    text-align: right;
    font-size: 0.85rem;
    color: #666;
    margin-top: 0.25rem;
}

.form-actions {
    display: flex;
    gap: 1rem;
    margin-top: 1.5rem;
}

.btn-next, .btn-back, .btn-submit, .btn-add, .btn-remove {
    padding: 0.6rem 1.5rem;
    border: none;
    border-radius: 4px;
    font-size: 1rem;
    cursor: pointer;
    transition: opacity 0.2s;
}

.btn-next {
    background: #0d6efd;
    color: white;
}

.btn-back {
    background: #6c757d;
    color: white;
}

.btn-submit {
    background: #198754;
    color: white;
}

.btn-add {
    background: #0d6efd22;
    color: #0d6efd;
    border: 1px dashed #0d6efd;
    margin-top: 1rem;
}

.btn-remove {
    background: #dc354522;
    color: #dc3545;
    border: 1px solid #dc3545;
    padding: 0.3rem 1rem;
    font-size: 0.85rem;
}

.btn-next:disabled, .btn-submit:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.validation-error {
    color: #dc3545;
    background: #dc354511;
    border: 1px solid #dc354544;
    padding: 0.75rem;
    border-radius: 4px;
    margin-top: 1rem;
}

fieldset.work-entry, fieldset.reference-entry {
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 1rem;
    margin-bottom: 1rem;
}

fieldset legend {
    font-weight: bold;
    padding: 0 0.5rem;
}

.review-section {
    border-bottom: 1px solid #eee;
    padding-bottom: 1rem;
    margin-bottom: 1rem;
}

.review-section h3 {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.edit-link {
    font-size: 0.85rem;
    color: #0d6efd;
    cursor: pointer;
    text-decoration: underline;
}

.review-section dl {
    display: grid;
    grid-template-columns: auto 1fr;
    gap: 0.3rem 1rem;
}

.review-section dt {
    font-weight: 600;
}

.review-work-entry, .review-reference {
    margin-bottom: 0.75rem;
    padding: 0.5rem;
    background: #f8f9fa;
    border-radius: 4px;
}

.cover-letter-preview {
    white-space: pre-wrap;
    background: #f8f9fa;
    padding: 1rem;
    border-radius: 4px;
}

.submission-confirmation {
    text-align: center;
    padding: 2rem;
    background: #19875411;
    border: 1px solid #19875444;
    border-radius: 8px;
}

.submission-confirmation h2 {
    color: #198754;
}

